import React from 'react';
import { ChickenData, GamePhase } from '../types';

interface ChickenProps {
  chicken: ChickenData;
  phase: GamePhase;
  isWinner: boolean;
}

const ChickenSVG: React.FC<{ color: string; isRunning: boolean; isWinner: boolean; id: number }> = ({
  color,
  isRunning,
  isWinner,
  id,
}) => {
  const darkColor = darkenColor(color);
  const animClass = isWinner
    ? 'chicken-winner'
    : isRunning
    ? `chicken-run chicken-run-${id}`
    : 'chicken-idle';

  return (
    <svg
      className={`chicken-svg ${animClass}`}
      width="64"
      height="52"
      viewBox="0 0 64 52"
      xmlns="http://www.w3.org/2000/svg"
    >
      {/* Tail feathers */}
      <ellipse cx="10" cy="24" rx="10" ry="5" fill={darkColor} transform="rotate(-30 10 24)" />
      <ellipse cx="8" cy="21" rx="9" ry="4" fill={color} transform="rotate(-45 8 21)" />
      <ellipse cx="7" cy="18" rx="8" ry="3.5" fill={darkColor} transform="rotate(-60 7 18)" />

      {/* Body */}
      <ellipse cx="32" cy="28" rx="18" ry="13" fill={color} />
      {/* Wing */}
      <ellipse cx="30" cy="27" rx="11" ry="7" fill={darkColor} transform="rotate(-10 30 27)" />
      <ellipse cx="29" cy="26" rx="8" ry="5" fill={color} transform="rotate(-10 29 26)" />

      {/* Neck */}
      <ellipse cx="46" cy="22" rx="6" ry="9" fill={color} />

      {/* Head */}
      <circle cx="50" cy="15" r="9" fill={color} />

      {/* Comb */}
      <path d="M46 8 Q48 3 50 7 Q52 2 54 6 Q55 1 56 5 L55 8 Z" fill="#e03030" />

      {/* Wattle */}
      <ellipse cx="54" cy="19" rx="3" ry="4" fill="#e03030" />

      {/* Eye */}
      <circle cx="53" cy="13" r="2.5" fill="white" />
      <circle cx="54" cy="13" r="1.5" fill="#222" />
      <circle cx="54.5" cy="12.5" r="0.5" fill="white" />

      {/* Beak */}
      <path d="M58 15 L64 16 L58 18 Z" fill="#e88c20" />

      {/* Legs */}
      <g className={isRunning || isWinner ? 'legs-run' : 'legs-idle'}>
        {/* Left leg */}
        <line x1="28" y1="40" x2="24" y2="48" stroke={darkColor} strokeWidth="2.5" strokeLinecap="round" />
        <line x1="24" y1="48" x2="19" y2="50" stroke={darkColor} strokeWidth="2" strokeLinecap="round" />
        <line x1="24" y1="48" x2="23" y2="52" stroke={darkColor} strokeWidth="2" strokeLinecap="round" />
        {/* Right leg */}
        <line x1="36" y1="40" x2="38" y2="48" stroke={darkColor} strokeWidth="2.5" strokeLinecap="round" />
        <line x1="38" y1="48" x2="44" y2="50" stroke={darkColor} strokeWidth="2" strokeLinecap="round" />
        <line x1="38" y1="48" x2="38" y2="52" stroke={darkColor} strokeWidth="2" strokeLinecap="round" />
      </g>
    </svg>
  );
};

function darkenColor(hex: string): string {
  const map: Record<string, string> = {
    '#f5f5f5': '#d0d0d0',
    '#2a2a2a': '#111111',
    '#555555': '#333333',
    '#cccccc': '#aaaaaa',
  };
  return map[hex] ?? '#888888';
}

const Chicken: React.FC<ChickenProps> = ({ chicken, phase, isWinner }) => {
  // Position: chicken starts at ~38% of track (after the lane number panel)
  // and moves to right based on chicken.position (0–100)
  // We'll map position 0→100 to CSS left 38%→92%
  const startPct = 38;
  const endPct = 90;
  const leftPct = startPct + (chicken.position / 100) * (endPct - startPct);

  return (
    <div
      className={`chicken-wrapper ${isWinner ? 'chicken-winner-wrapper' : ''}`}
      style={{ left: `${leftPct}%` }}
    >
      <ChickenSVG
        color={chicken.bodyColor}
        isRunning={phase === 'racing'}
        isWinner={isWinner}
        id={chicken.id}
      />
    </div>
  );
};

export default Chicken;
